// Trophic Level Energy Transfer Calculator
// Based on 10% energy transfer rule

FUNCTION calculateEnergyAtLevel(baseEnergy, trophicLevel):
 energy = baseEnergy
 FOR i = 1 TO trophicLevel - 1:
 energy = energy * 0.10 // 90% loss at each level
 RETURN energy

FUNCTION simulateFoodChain(producers, consumers, predators):
 producerEnergy = producers

 // Primary production
 PRINT "Trophic Level 1 (Producers): " + producerEnergy + " kcal"

 // Primary consumers
 primaryConsumerEnergy = calculateEnergyAtLevel(producerEnergy, 2)
 PRINT "Trophic Level 2 (Primary Consumers): " + primaryConsumerEnergy + " kcal"

 // Secondary consumers 
 secondaryConsumerEnergy = calculateEnergyAtLevel(producerEnergy, 3)
 PRINT "Trophic Level 3 (Secondary Consumers): " + secondaryConsumerEnergy + " kcal"

 // Apex predators
 apexEnergy = calculateEnergyAtLevel(producerEnergy, 4)
 PRINT "Trophic Level 4 (Apex Predators): " + apexEnergy + " kcal"

 RETURN efficiency = (apexEnergy / producerEnergy) * 100

// Example: 10,000 kcal of phytoplankton
result = simulateFoodChain(10000, 0, 0)
